@inject IJSRuntime JS
@implements IAsyncDisposable
@rendermode InteractiveServer

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag and drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var file in _files)
        {
            <li class="file-entry @(file.IsOversize ? "file-error" : "")">
                @if (file.IsOversize)
                {
                    <span class="error-message">@file.Info.Name — exceeds 10 MB limit (@FormatSize(file.Info.Size))</span>
                }
                else
                {
                    <span>@file.Info.Name — @FormatSize(file.Info.Size) — @file.Info.Type</span>
                }
                <button class="remove-btn" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private bool _isDragOver;
    private readonly List<DroppedFile> _files = new();
    private FileDropZoneInterop? _interop;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _interop = new FileDropZoneInterop(JS);
            await _interop.InitializeAsync(_dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnDragStateChanged(bool isDragOver)
    {
        await InvokeAsync(() =>
        {
            _isDragOver = isDragOver;
            StateHasChanged();
        });
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] files)
    {
        await InvokeAsync(async () =>
        {
            _isDragOver = false;
            foreach (var file in files)
            {
                _files.Add(new DroppedFile(file, file.Size > MaxFileSizeBytes));
            }
            StateHasChanged();
            await NotifyParent();
        });
    }

    private async Task RemoveFile(DroppedFile file)
    {
        _files.Remove(file);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.IsOversize).Select(f => f.Info).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_interop is not null)
                await _interop.DisposeAsync();
        }
        catch (JSDisconnectedException) { }

        _dotNetRef?.Dispose();
    }

    private sealed record DroppedFile(FileInfo Info, bool IsOversize);
}

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_3bac1f6a1db44aca92a3bdbf0dd4d44e.Components;

public sealed class FileDropZoneInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/FileDropZone.razor.js";
    internal const string InitMethod = "initialize";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public FileDropZoneInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync(ElementReference element, DotNetObjectReference<FileDropZone> dotNetRef)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitMethod, element, dotNetRef);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

const ON_DRAG_STATE_CHANGED = 'OnDragStateChanged';
const ON_FILES_DROPPED = 'OnFilesDropped';

class DropZoneHandler {
    #element;
    #dotNetRef;
    #abortController;

    constructor(element, dotNetRef) {
        this.#element = element;
        this.#dotNetRef = dotNetRef;
        this.#abortController = new AbortController();
    }

    start() {
        const signal = this.#abortController.signal;

        this.#element.addEventListener('dragover', (e) => {
            e.preventDefault();
        }, { signal });

        this.#element.addEventListener('dragenter', async (e) => {
            e.preventDefault();
            try {
                await this.#dotNetRef.invokeMethodAsync(ON_DRAG_STATE_CHANGED, true);
            } catch { }
        }, { signal });

        this.#element.addEventListener('dragleave', async (e) => {
            e.preventDefault();
            if (!this.#element.contains(e.relatedTarget)) {
                try {
                    await this.#dotNetRef.invokeMethodAsync(ON_DRAG_STATE_CHANGED, false);
                } catch { }
            }
        }, { signal });

        this.#element.addEventListener('drop', async (e) => {
            e.preventDefault();
            const files = Array.from(e.dataTransfer.files).map(f => ({
                name: f.name,
                size: f.size,
                type: f.type || 'application/octet-stream'
            }));
            try {
                await this.#dotNetRef.invokeMethodAsync(ON_FILES_DROPPED, files);
            } catch { }
        }, { signal });
    }

    dispose() {
        this.#abortController.abort();
    }
}

let handler;

export function initialize(element, dotNetRef) {
    handler = new DropZoneHandler(element, dotNetRef);
    handler.start();
}

export function dispose() {
    handler?.dispose();
    handler = null;
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.remove-btn {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
}

.remove-btn:hover {
    background-color: #dc3545;
    color: white;
}

@inject IJSRuntime JS
@implements IAsyncDisposable
@rendermode InteractiveServer

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag and drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var file in _files)
        {
            <li class="file-entry @(file.IsOversize ? "file-error" : "")">
                @if (file.IsOversize)
                {
                    <span class="error-message">@file.Info.Name — exceeds 10 MB limit (@FormatSize(file.Info.Size))</span>
                }
                else
                {
                    <span>@file.Info.Name — @FormatSize(file.Info.Size) — @file.Info.Type</span>
                }
                <button class="remove-btn" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private bool _isDragOver;
    private readonly List<DroppedFile> _files = new();
    private FileDropZoneInterop? _interop;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _interop = new FileDropZoneInterop(JS);
            await _interop.InitializeAsync(_dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnDragStateChanged(bool isDragOver)
    {
        await InvokeAsync(() =>
        {
            _isDragOver = isDragOver;
            StateHasChanged();
        });
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] files)
    {
        await InvokeAsync(async () =>
        {
            _isDragOver = false;
            foreach (var file in files)
            {
                _files.Add(new DroppedFile(file, file.Size > MaxFileSizeBytes));
            }
            StateHasChanged();
            await NotifyParent();
        });
    }

    private async Task RemoveFile(DroppedFile file)
    {
        _files.Remove(file);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files.Where(f => !f.IsOversize).Select(f => f.Info).ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_interop is not null)
                await _interop.DisposeAsync();
        }
        catch (JSDisconnectedException) { }

        _dotNetRef?.Dispose();
    }

    private sealed record DroppedFile(FileInfo Info, bool IsOversize);
}

