const ON_DRAG_STATE_CHANGED = 'OnDragStateChanged';
const ON_FILES_DROPPED = 'OnFilesDropped';

class DropZoneHandler {
    #element;
    #dotNetRef;
    #abortController;

    constructor(element, dotNetRef) {
        this.#element = element;
        this.#dotNetRef = dotNetRef;
        this.#abortController = new AbortController();
    }

    start() {
        const signal = this.#abortController.signal;

        this.#element.addEventListener('dragover', (e) => {
            e.preventDefault();
        }, { signal });

        this.#element.addEventListener('dragenter', async (e) => {
            e.preventDefault();
            try {
                await this.#dotNetRef.invokeMethodAsync(ON_DRAG_STATE_CHANGED, true);
            } catch { }
        }, { signal });

        this.#element.addEventListener('dragleave', async (e) => {
            e.preventDefault();
            if (!this.#element.contains(e.relatedTarget)) {
                try {
                    await this.#dotNetRef.invokeMethodAsync(ON_DRAG_STATE_CHANGED, false);
                } catch { }
            }
        }, { signal });

        this.#element.addEventListener('drop', async (e) => {
            e.preventDefault();
            const files = Array.from(e.dataTransfer.files).map(f => ({
                name: f.name,
                size: f.size,
                type: f.type || 'application/octet-stream'
            }));
            try {
                await this.#dotNetRef.invokeMethodAsync(ON_FILES_DROPPED, files);
            } catch { }
        }, { signal });
    }

    dispose() {
        this.#abortController.abort();
    }
}

let handler;

export function initialize(element, dotNetRef) {
    handler = new DropZoneHandler(element, dotNetRef);
    handler.start();
}

export function dispose() {
    handler?.dispose();
    handler = null;
}

